function createRequestObject() {
    var tempRequestObj;
    //depending on what the browser supports, use the right way to create the XMLHttpRequest object
    if (window.XMLHttpRequest) {        // Mozilla, Safari would use this method ...
        tempRequestObj = new XMLHttpRequest();
    } else if (window.ActiveXObject) {        // IE would use this method ...
        tempRequestObj = new ActiveXObject("Microsoft.XMLHTTP");
    }
    return tempRequestObj;
}


