    requestObj.send(packet);
    var returnstring = requestObj.responseText;
    returnstring = returnstring.replace("<?xml version=\"1.0\" encoding=\"utf-8\"?>", "");
    returnstring = returnstring.replace("<soap:Envelope xmlns:soap=\"http://schemas.xmlsoap.org/soap/envelope/\"", "");
    returnstring = returnstring.replace("xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\"", "");
    returnstring = returnstring.replace("xmlns:xsd=\"http://www.w3.org/2001/XMLSchema\">", "");
    returnstring = returnstring.replace("<soap:Body>", "");
    returnstring = returnstring.replace("<getRoundCalendarForUPRNResponse xmlns=\"http://webaspx-collections.azurewebsites.net/\">", "");
    returnstring = returnstring.replace("<getRoundCalendarForUPRNResult>", "");
    returnstring = returnstring.replace("</getRoundCalendarForUPRNResult>", "");
    returnstring = returnstring.replace("</getRoundCalendarForUPRNResponse>", "");
    returnstring = returnstring.replace("</soap:Body>", "");
    returnstring = returnstring.replace("</soap:Envelope>", "");
    returnstring = returnstring.split("&gt;").join(">");
    returnstring = returnstring.split("&lt;").join("<");
